import React from 'react';
import { Router, Route, IndexRoute } from 'react-router';


import Main from './components/Main';
import About from './components/About';
import Work from './components/Main';
import Contact from './components/Main';
import References from './components/Main';
import AhsanMemon from './components/Main';
import SumairBaloch from './components/Main';
import NajamLaghari from './components/Main';

const Routes = (props) => (
  <Router {...props}>
    <Route path="/" component={Main} />
    <Route path='/about' component={About}/>
    <Route path= "/work" component={Work} />
    <Route path= "/contact" component={Contact} />
    <Route path= "/references" component={References} />
    <Route path= "/ahsanmemon" component={AhsanMemon} />
    <Route path= "/sumairbaloch" component={SumairBaloch} />
	<Route path= "/najamlaghari" component={NajamLaghari} />
   
   { /* <Route path="/about" component={About} />
    	<IndexRoute component = {Home}/>
    <Route path='/adminSignup' component={AdminSignup}/>
    <Route path="/studentsignup" component={StudentSignup} />
    <Route path='/teacherSignup' component={TeacherSignup}/>
    <Route path="/adminLogin" component={AdminLogin} />
    <Route path='/studentLogin' component={StudentLogin}/>
    <Route path='/teacherLogin' component={TeacherLogin}/>
    <Route path='/studentDashboard' component={StudentDashboard} />
    <Route path="*" component={NotFound} /> */ }
  
  </Router>
);

export default Routes;



